import React from 'react';
import { Link } from 'react-router-dom';

const UserDashboard = () => {
  const upcomingAppointments = [
    { id: 1, doctor: 'Dr. Smith', datetime: '2024-07-01 10:00', status: 'Confirmed' },
    { id: 2, doctor: 'Dr. Jones', datetime: '2024-07-05 14:00', status: 'Pending' },
  ];

  return (
      <div className="min-h-screen bg-gradient-to-br from-green-100 to-blue-100 py-10 px-4 sm:px-10 text-gray-900">
        {/* Welcome */}
        <div className="mb-10 text-center">
          <h1 className="text-4xl font-bold text-green-700 mb-2">Welcome to Your Dashboard</h1>
          <p className="text-gray-600 text-lg">Manage your appointments and settings easily.</p>
        </div>

        {/* Upcoming Appointments */}
        <section className="mb-12">
          <h2 className="text-2xl font-semibold text-gray-800 mb-4">Upcoming Appointments</h2>
          {upcomingAppointments.length === 0 ? (
              <p className="text-gray-500">You have no upcoming appointments.</p>
          ) : (
              <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
                {upcomingAppointments.map((appt) => (
                    <div
                        key={appt.id}
                        className="bg-white rounded-lg shadow-md p-5 border-l-4 border-green-500 hover:shadow-lg transition"
                    >
                      <p className="font-semibold text-lg text-green-700 mb-2">
                        ️ Doctor: {appt.doctor}
                      </p>
                      <p className="text-gray-700"> Date & Time: {appt.datetime}</p>
                      <p className="text-gray-700">
                         Status:{' '}
                        <span
                            className={`font-medium ${
                                appt.status === 'Confirmed'
                                    ? 'text-green-600'
                                    : appt.status === 'Pending'
                                        ? 'text-yellow-600'
                                        : 'text-red-600'
                            }`}
                        >
                    {appt.status}
                  </span>
                      </p>
                    </div>
                ))}
              </div>
          )}
        </section>

        {/* Quick Actions */}
        <section className="mb-6">
          <h2 className="text-2xl font-semibold text-gray-800 mb-4">Quick Actions</h2>
          <div className="flex flex-wrap gap-4">
            <Link
                to="/app/edit-profile"
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow"
            >
               Edit Profile
            </Link>
            <Link
                to="/app/change-password"
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow"
            >
               Change Password
            </Link>
            <Link
                to="/app/appointments"
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow"
            >
               View Appointments
            </Link>
            <Link
                to="/app/book-appointment"
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow"
            >
              🩺 Book Appointment
            </Link>
          </div>
        </section>
      </div>
  );
};

export default UserDashboard;
